sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?county ?record ?recordDate ?numOutages ?ntl ?map ?locator
WHERE {
  ?county a goo:County ;
          goo:locatedInState gokg:FloridaState .
  ?record a goo:CustomerOutageRecord ;
          goo:representsCounty ?county ;
          goo:recordDateTime ?recordDate ;
          goo:numberOfOutages ?numOutages .
  ?ntl a goo:NTLImage ;
       goo:representsCounty ?county ;
       goo:acquisitionDateTime ?imageDate ;
       goo:hasOutageMap ?map ;
       goo:sourceDownloadUrl ?locator .
  ?map a goo:OutageMap .
  FILTER (?numOutages > 250000)
  FILTER (?imageDate >= "2022-09-28T00:00:00Z"^^xsd:dateTime && ?imageDate < "2022-10-03T00:00:00Z"^^xsd:dateTime)
  FILTER (?recordDate >= "2022-09-28T00:00:00Z"^^xsd:dateTime && ?recordDate < "2022-10-03T00:00:00Z"^^xsd:dateTime)
}
ORDER BY ?county ?recordDate
LIMIT 10
